import{_ as s,c as a,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Stage 2: PRD - Generate Product Requirements Document | Agent App Factory Tutorial","description":"Learn how the PRD stage transforms structured product ideas into MVP-level product requirements documents. This tutorial explains the PRD Agent's responsibilities, how to use skills/prd/skill.md, the standard structure of prd.md, and the MoSCoW priority framework to help you quickly define MVP scope and priorities and write testable user stories and acceptance criteria independently.","frontmatter":{"title":"Stage 2: PRD - Generate Product Requirements Document | Agent App Factory Tutorial","sidebarTitle":"Generate Product Requirements Document","subtitle":"Stage 2: PRD - Generate Product Requirements Document","description":"Learn how the PRD stage transforms structured product ideas into MVP-level product requirements documents. This tutorial explains the PRD Agent's responsibilities, how to use skills/prd/skill.md, the standard structure of prd.md, and the MoSCoW priority framework to help you quickly define MVP scope and priorities and write testable user stories and acceptance criteria independently.","tags":["Pipeline","PRD","Product Requirements"],"prerequisite":["start-pipeline-overview","advanced-stage-bootstrap"],"order":90},"headers":[],"relativePath":"hyz1992/agent-app-factory/advanced/stage-prd/index.md","filePath":"hyz1992/agent-app-factory/advanced/stage-prd/index.md"}`),i={name:"hyz1992/agent-app-factory/advanced/stage-prd/index.md"};function o(l,e,r,p,c,d){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="stage-2-prd-generate-product-requirements-document" tabindex="-1">Stage 2: PRD - Generate Product Requirements Document <a class="header-anchor" href="#stage-2-prd-generate-product-requirements-document" aria-label="Permalink to &quot;Stage 2: PRD - Generate Product Requirements Document&quot;">​</a></h1><p>The PRD stage is the second stage of the Agent App Factory pipeline, responsible for transforming <code>input/idea.md</code> into a complete, MVP-level (Minimum Viable Product) product requirements document. This stage will clarify target users, core features, MVP scope, and non-goals, providing clear guidance for subsequent UI design and technical architecture.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will be able to:</p><ul><li>Transform <code>input/idea.md</code> into an <code>artifacts/prd/prd.md</code> document that follows the standard template</li><li>Understand the PRD Agent&#39;s responsibility boundaries (only define requirements, not technical implementation)</li><li>Master the MoSCoW feature priority framework to ensure MVP focuses on core value</li><li>Write high-quality user stories and verifiable acceptance criteria</li><li>Know which content belongs in the PRD and which should be in later stages</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>You may have a clear product idea (Bootstrap stage completed), but encounter difficulties when converting it to a requirements document:</p><ul><li>&quot;Don&#39;t know which features to include, worried about missing something or over-designing&quot;</li><li>&quot;Many features, but unsure which ones are essential for MVP&quot;</li><li>&quot;User stories written unclearly, development team can&#39;t understand them&quot;</li><li>&quot;Accidentally mixing technical implementation details into requirements, causing scope creep&quot;</li></ul><p>Unclear PRDs will lead to lack of clear guidance for subsequent UI design and code development, ultimately resulting in applications that deviate from your expectations or contain unnecessary complexity.</p><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p>When the Bootstrap stage is completed and the following conditions are met:</p><ol><li><strong>idea.md structuring completed</strong> (Bootstrap stage output)</li><li><strong>Haven&#39;t started UI design or technical architecture</strong> (these come in later stages)</li><li><strong>Want to clarify MVP scope</strong> (avoid feature over-design)</li><li><strong>Need to provide clear guidance for development and design</strong> (user stories, acceptance criteria)</li></ol><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to &quot;🎒 Before You Start&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>Before starting the PRD stage, ensure:</p><ul><li>✅ <a href="./../../start/init-project/">Project initialization completed</a></li><li>✅ <a href="./../../start/pipeline-overview/">Understood the 7-stage pipeline overview</a></li><li>✅ <a href="./../stage-bootstrap/">Bootstrap stage completed</a>, generated <code>input/idea.md</code></li><li>✅ AI assistant installed and configured (Claude Code recommended)</li></ul></div><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="what-is-the-prd-stage" tabindex="-1">What is the PRD Stage? <a class="header-anchor" href="#what-is-the-prd-stage" aria-label="Permalink to &quot;What is the PRD Stage?&quot;">​</a></h3><p><strong>PRD</strong> (Product Requirements Document) stage&#39;s core responsibility is <strong>defining what to do, not how to do it</strong>.</p><div class="info custom-block"><p class="custom-block-title">Not Technical Documentation</p><p>PRD Agent is not an architect or UI designer, it will not decide:</p><ul><li>❌ Which tech stack to use (React vs Vue, Express vs Koa)</li><li>❌ How to design the database (table structure, indexes)</li><li>❌ UI layout and interaction details (button positions, color schemes)</li></ul><p>Its task is:</p><ul><li>✅ Define target users and their pain points</li><li>✅ List core features and priorities</li><li>✅ Clarify MVP scope and non-goals</li><li>✅ Provide testable user stories and acceptance criteria</li></ul></div><h3 id="why-prd" tabindex="-1">Why PRD? <a class="header-anchor" href="#why-prd" aria-label="Permalink to &quot;Why PRD?&quot;">​</a></h3><p>Imagine you tell the construction team: &quot;I want to build a house&quot;</p><ul><li>❌ No blueprints: The construction team can only guess, possibly building a house you don&#39;t want to live in at all</li><li>✅ Detailed blueprints: Clearly specify the number of rooms, functional layout, material requirements, the construction team builds according to the drawings</li></ul><p>The PRD stage turns &quot;I want to build a house&quot; into detailed blueprints like &quot;three bedrooms, two living rooms, master bedroom facing south, open kitchen&quot;.</p><h3 id="moscow-feature-priority-framework" tabindex="-1">MoSCoW Feature Priority Framework <a class="header-anchor" href="#moscow-feature-priority-framework" aria-label="Permalink to &quot;MoSCoW Feature Priority Framework&quot;">​</a></h3><p>The PRD stage uses the <strong>MoSCoW framework</strong> to classify features, ensuring MVP focuses on core value:</p><table tabindex="0"><thead><tr><th>Category</th><th>Definition</th><th>Judgment Criteria</th><th>Example</th></tr></thead><tbody><tr><td><strong>Must Have</strong></td><td>Features absolutely essential for MVP</td><td>Without it, the product cannot deliver core value</td><td>Expense tracking app: Add expense record, view expense list</td></tr><tr><td><strong>Should Have</strong></td><td>Important but non-blocking features</td><td>Users will noticeably miss it, but workarounds exist</td><td>Expense tracking app: Export reports, category statistics</td></tr><tr><td><strong>Could Have</strong></td><td>Nice-to-have features</td><td>Doesn&#39;t affect core experience, users won&#39;t specifically notice absence</td><td>Expense tracking app: Budget alerts, multi-currency support</td></tr><tr><td><strong>Won&#39;t Have</strong></td><td>Explicitly excluded features</td><td>Irrelevant to core value or high technical complexity</td><td>Expense tracking app: Social sharing, investment advice</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">MVP Core</p><p>Must Have features should be controlled within 5-7 items, ensuring MVP focuses on core value and avoiding scope creep.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-confirm-bootstrap-stage-completed" tabindex="-1">Step 1: Confirm Bootstrap Stage Completed <a class="header-anchor" href="#step-1-confirm-bootstrap-stage-completed" aria-label="Permalink to &quot;Step 1: Confirm Bootstrap Stage Completed&quot;">​</a></h3><p>Before starting the PRD stage, ensure <code>input/idea.md</code> exists and content meets standards.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check if idea.md exists</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input/idea.md</span></span></code></pre></div><p><strong>What you should see</strong>: A structured document with sections including brief description, problem, target users, core value, assumptions, and non-goals.</p><div class="tip custom-block"><p class="custom-block-title">If idea.md doesn&#39;t meet standards</p><p>Return to <a href="./../stage-bootstrap/">Bootstrap stage</a> to regenerate, or manually edit to supplement information.</p></div><h3 id="step-2-start-pipeline-to-prd-stage" tabindex="-1">Step 2: Start Pipeline to PRD Stage <a class="header-anchor" href="#step-2-start-pipeline-to-prd-stage" aria-label="Permalink to &quot;Step 2: Start Pipeline to PRD Stage&quot;">​</a></h3><p>Execute in the Factory project directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If pipeline is already started, continue to PRD stage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prd</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or start pipeline from scratch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p>CLI will display current status and available stages, and generate PRD Agent&#39;s assistant instructions.</p><h3 id="step-3-ai-assistant-reads-prd-agent-definition" tabindex="-1">Step 3: AI Assistant Reads PRD Agent Definition <a class="header-anchor" href="#step-3-ai-assistant-reads-prd-agent-definition" aria-label="Permalink to &quot;Step 3: AI Assistant Reads PRD Agent Definition&quot;">​</a></h3><p>AI assistant (such as Claude Code) will automatically read <code>agents/prd.agent.md</code>, understanding its responsibilities and constraints.</p><div class="info custom-block"><p class="custom-block-title">PRD Agent Responsibilities</p><p>PRD Agent can only:</p><ul><li>Read <code>input/idea.md</code></li><li>Write to <code>artifacts/prd/prd.md</code></li><li>Use the thinking frameworks and decision principles in <code>skills/prd/skill.md</code></li></ul><p>It cannot:</p><ul><li>Discuss any technical implementation details or UI design</li><li>Read other files (including upstream artifacts)</li><li>Write to other directories</li></ul></div><h3 id="step-4-load-skills-prd-skill-md" tabindex="-1">Step 4: Load skills/prd/skill.md <a class="header-anchor" href="#step-4-load-skills-prd-skill-md" aria-label="Permalink to &quot;Step 4: Load skills/prd/skill.md&quot;">​</a></h3><p>PRD Agent will load <code>skills/prd/skill.md</code>, obtaining the following guidance:</p><p><strong>Thinking Framework</strong>:</p><ul><li>Target users: Who will use it? Background, role, pain points?</li><li>Core problem: What fundamental problem does the product solve?</li><li>Core value: Why is this solution valuable? What are the advantages over competitors?</li><li>Success metrics: How to measure success?</li></ul><p><strong>MoSCoW Feature Priority</strong>:</p><ul><li>Must Have: Features absolutely essential for MVP</li><li>Should Have: Important but non-blocking features</li><li>Could Have: Nice-to-have features</li><li>Won&#39;t Have: Explicitly excluded features</li></ul><p><strong>User Story Writing Guidelines</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>As a [role/user type]</span></span>
<span class="line"><span>I want [feature/operation]</span></span>
<span class="line"><span>So that [business value/goal]</span></span></code></pre></div><p><strong>PRD Document Structure Requirements</strong> (8 sections):</p><ol><li>Overview</li><li>Target User Persona</li><li>Core Value Proposition</li><li>Feature Requirements (MoSCoW classification)</li><li>User Flow</li><li>Non-goals (Won&#39;t Have)</li><li>Success Metrics</li><li>Assumptions and Risks</li></ol><h3 id="step-5-generate-prd-document" tabindex="-1">Step 5: Generate PRD Document <a class="header-anchor" href="#step-5-generate-prd-document" aria-label="Permalink to &quot;Step 5: Generate PRD Document&quot;">​</a></h3><p>AI assistant will generate a complete PRD document based on the content of <code>input/idea.md</code>, using the thinking frameworks and decision principles from the skill.</p><p><strong>What PRD Agent Will Do</strong>:</p><ol><li>Read <code>input/idea.md</code>, extract key elements (target users, problems, core value, etc.)</li><li>Classify features according to MoSCoW framework</li><li>Write user stories and acceptance criteria for Must Have features</li><li>List non-goals to prevent scope creep</li><li>Provide quantifiable success metrics</li><li>Write the organized document to <code>artifacts/prd/prd.md</code></li></ol><div class="tip custom-block"><p class="custom-block-title">Key Constraint</p><p>PRD Agent is prohibited from discussing technical implementation details or UI design. If such content is found, PRD Agent will refuse to write it.</p></div><h3 id="step-6-confirm-prd-md-content" tabindex="-1">Step 6: Confirm prd.md Content <a class="header-anchor" href="#step-6-confirm-prd-md-content" aria-label="Permalink to &quot;Step 6: Confirm prd.md Content&quot;">​</a></h3><p>After PRD Agent completes, it will generate <code>artifacts/prd/prd.md</code>. You need to carefully check:</p><p><strong>Checkpoints ✅</strong>:</p><ol><li><p><strong>Are target users specific?</strong></p><ul><li>✅ Have specific personas (age/profession/technical ability/use scenario/pain points)</li><li>❌ Vague: &quot;Everyone&quot; or &quot;People who need to track expenses&quot;</li></ul></li><li><p><strong>Is the core problem clear?</strong></p><ul><li>✅ Describes the problem users encounter in real-world scenarios</li><li>❌ Vague: &quot;User experience is poor&quot;</li></ul></li><li><p><strong>Is core value quantifiable?</strong></p><ul><li>✅ Has specific benefits (save 80% time, improve 50% efficiency)</li><li>❌ Vague: &quot;Improve efficiency&quot;, &quot;better experience&quot;</li></ul></li><li><p><strong>Are Must Have features focused?</strong></p><ul><li>✅ No more than 5-7 core features</li><li>❌ Too many features or includes secondary features</li></ul></li><li><p><strong>Does each Must Have feature have a user story?</strong></p><ul><li>✅ Uses standard format (As a... I want... so that...)</li><li>❌ Missing user story or incorrect format</li></ul></li><li><p><strong>Are acceptance criteria verifiable?</strong></p><ul><li>✅ Has specific verifiable criteria (can input amount, displays in list)</li><li>❌ Vague (&quot;user-friendly&quot;, &quot;smooth experience&quot;)</li></ul></li><li><p><strong>Are Should Have and Won&#39;t Have clearly listed?</strong></p><ul><li>✅ Should Have marked as &quot;future iteration&quot; with reasons</li><li>✅ Won&#39;t Have explains why it&#39;s excluded</li><li>❌ Missing or too few</li></ul></li><li><p><strong>Are success metrics quantifiable?</strong></p><ul><li>✅ Has specific values (user retention rate &gt; 30%, task completion time &lt; 30 seconds)</li><li>❌ Vague (&quot;users like it&quot;, &quot;good experience&quot;)</li></ul></li><li><p><strong>Are assumptions verifiable?</strong></p><ul><li>✅ Can be verified through user research</li><li>❌ Subjective judgment (&quot;users will like it&quot;)</li></ul></li><li><p><strong>Does it contain technical implementation details or UI design?</strong></p><ul><li>✅ No technical details and UI descriptions</li><li>❌ Includes tech stack choices, database design, UI layout, etc.</li></ul></li></ol><h3 id="step-7-choose-continue-retry-or-pause" tabindex="-1">Step 7: Choose Continue, Retry, or Pause <a class="header-anchor" href="#step-7-choose-continue-retry-or-pause" aria-label="Permalink to &quot;Step 7: Choose Continue, Retry, or Pause&quot;">​</a></h3><p>After confirmation, CLI will display options:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Please</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> choose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> an</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> action:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1] Continue (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">enter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> UI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[2] Retry (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">regenerate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prd.md</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[3] Pause (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">continue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> later</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Recommended: Check in code editor first</p><p>Before confirming in the AI assistant, open <code>artifacts/prd/prd.md</code> in your code editor and check word by word. Once you enter the UI stage, modification costs will be higher.</p></div><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="pitfall-1-too-many-must-have-features" tabindex="-1">Pitfall 1: Too Many Must Have Features <a class="header-anchor" href="#pitfall-1-too-many-must-have-features" aria-label="Permalink to &quot;Pitfall 1: Too Many Must Have Features&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Must Have:</span></span>
<span class="line"><span>1. Add expense record</span></span>
<span class="line"><span>2. View expense list</span></span>
<span class="line"><span>3. Export reports</span></span>
<span class="line"><span>4. Category statistics</span></span>
<span class="line"><span>5. Budget alerts</span></span>
<span class="line"><span>6. Multi-currency support</span></span>
<span class="line"><span>7. Social sharing</span></span>
<span class="line"><span>8. Investment advice</span></span></code></pre></div><p><strong>Consequence</strong>: MVP scope too large, long development cycle, high risk.</p><p><strong>Recommendation</strong>: Control to 5-7 core features:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Must Have:</span></span>
<span class="line"><span>1. Add expense record</span></span>
<span class="line"><span>2. View expense list</span></span>
<span class="line"><span>3. Select expense category</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Should Have (future iteration):</span></span>
<span class="line"><span>4. Export reports</span></span>
<span class="line"><span>5. Category statistics</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Won&#39;t Have (explicitly excluded):</span></span>
<span class="line"><span>6. Social sharing (irrelevant to core value)</span></span>
<span class="line"><span>7. Investment advice (requires professional qualifications, high technical complexity)</span></span></code></pre></div><h3 id="pitfall-2-missing-or-incorrect-user-story-format" tabindex="-1">Pitfall 2: Missing or Incorrect User Story Format <a class="header-anchor" href="#pitfall-2-missing-or-incorrect-user-story-format" aria-label="Permalink to &quot;Pitfall 2: Missing or Incorrect User Story Format&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Feature: Add expense record</span></span>
<span class="line"><span>Description: Users can add expense records</span></span></code></pre></div><p><strong>Consequence</strong>: Development team doesn&#39;t know who they&#39;re building for, what problem they&#39;re solving.</p><p><strong>Recommendation</strong>: Use standard format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Feature: Add expense record</span></span>
<span class="line"><span>User Story: As a budget-conscious user</span></span>
<span class="line"><span>I want to record every expense</span></span>
<span class="line"><span>So I can understand where my money goes and control my budget</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Acceptance Criteria:</span></span>
<span class="line"><span>- Can input expense amount and description</span></span>
<span class="line"><span>- Can select expense category</span></span>
<span class="line"><span>- Record immediately displays in expense list</span></span>
<span class="line"><span>- Shows current date and time</span></span></code></pre></div><h3 id="pitfall-3-unverifiable-acceptance-criteria" tabindex="-1">Pitfall 3: Unverifiable Acceptance Criteria <a class="header-anchor" href="#pitfall-3-unverifiable-acceptance-criteria" aria-label="Permalink to &quot;Pitfall 3: Unverifiable Acceptance Criteria&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Acceptance Criteria:</span></span>
<span class="line"><span>- User interface is friendly</span></span>
<span class="line"><span>- Operations are smooth</span></span>
<span class="line"><span>- Good experience</span></span></code></pre></div><p><strong>Consequence</strong>: Cannot be tested, development team doesn&#39;t know what counts as &quot;friendly&quot;, &quot;smooth&quot;, &quot;good&quot;.</p><p><strong>Recommendation</strong>: Write specific verifiable criteria:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Acceptance Criteria:</span></span>
<span class="line"><span>- Can input expense amount and description</span></span>
<span class="line"><span>- Can select from 10 preset categories</span></span>
<span class="line"><span>- Record displays in expense list within 1 second</span></span>
<span class="line"><span>- Automatically records current date and time</span></span></code></pre></div><h3 id="pitfall-4-target-user-description-too-vague" tabindex="-1">Pitfall 4: Target User Description Too Vague <a class="header-anchor" href="#pitfall-4-target-user-description-too-vague" aria-label="Permalink to &quot;Pitfall 4: Target User Description Too Vague&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Target users: Everyone who needs to track expenses</span></span></code></pre></div><p><strong>Consequence</strong>: Subsequent UI design and technical architecture lack clear direction.</p><p><strong>Recommendation</strong>: Clarify personas:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Main user group:</span></span>
<span class="line"><span>- Role: Young professionals aged 18-30 who just started working</span></span>
<span class="line"><span>- Age: 18-30 years old</span></span>
<span class="line"><span>- Technical ability: Intermediate, familiar with smartphone apps</span></span>
<span class="line"><span>- Use scenario: Record immediately after daily consumption, check statistics at month-end</span></span>
<span class="line"><span>- Pain points: Discover overspending at month-end, don&#39;t know where money went, no budget control</span></span></code></pre></div><h3 id="pitfall-5-missing-or-too-few-non-goals" tabindex="-1">Pitfall 5: Missing or Too Few Non-goals <a class="header-anchor" href="#pitfall-5-missing-or-too-few-non-goals" aria-label="Permalink to &quot;Pitfall 5: Missing or Too Few Non-goals&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Non-goals: None</span></span></code></pre></div><p><strong>Consequence</strong>: Subsequent PRD and Code stages may over-design, increasing technical complexity.</p><p><strong>Recommendation</strong>: List at least 3 items:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Non-goals (Out of Scope):</span></span>
<span class="line"><span>- Social sharing functionality (MVP focuses on personal expense tracking)</span></span>
<span class="line"><span>- Financial advice and investment analysis (requires professional qualifications, beyond core value)</span></span>
<span class="line"><span>- Integration with third-party financial systems (high technical complexity, MVP doesn&#39;t need it)</span></span>
<span class="line"><span>- Complex data analysis and reports (Should Have, future iteration)</span></span></code></pre></div><h3 id="pitfall-6-includes-technical-implementation-details" tabindex="-1">Pitfall 6: Includes Technical Implementation Details <a class="header-anchor" href="#pitfall-6-includes-technical-implementation-details" aria-label="Permalink to &quot;Pitfall 6: Includes Technical Implementation Details&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Feature: Add expense record</span></span>
<span class="line"><span>Technical implementation: Use React Hook Form for form management, API endpoint POST /api/expenses</span></span></code></pre></div><p><strong>Consequence</strong>: PRD Agent will refuse these contents (only define requirements, not technical implementation).</p><p><strong>Recommendation</strong>: Only say &quot;what to do&quot;, not &quot;how to do it&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Feature: Add expense record</span></span>
<span class="line"><span>User Story: As a budget-conscious user</span></span>
<span class="line"><span>I want to record every expense</span></span>
<span class="line"><span>So I can understand where my money goes and control my budget</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Acceptance Criteria:</span></span>
<span class="line"><span>- Can input expense amount and description</span></span>
<span class="line"><span>- Can select expense category</span></span>
<span class="line"><span>- Record immediately displays in expense list</span></span>
<span class="line"><span>- Shows current date and time</span></span></code></pre></div><h3 id="pitfall-7-unquantifiable-success-metrics" tabindex="-1">Pitfall 7: Unquantifiable Success Metrics <a class="header-anchor" href="#pitfall-7-unquantifiable-success-metrics" aria-label="Permalink to &quot;Pitfall 7: Unquantifiable Success Metrics&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Success Metrics:</span></span>
<span class="line"><span>- Users like our app</span></span>
<span class="line"><span>- Experience is smooth</span></span>
<span class="line"><span>- High user retention</span></span></code></pre></div><p><strong>Consequence</strong>: Cannot measure whether the product is successful.</p><p><strong>Recommendation</strong>: Write quantifiable metrics:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Success Metrics:</span></span>
<span class="line"><span>Product Goals:</span></span>
<span class="line"><span>- Acquire 100 active users in the first month</span></span>
<span class="line"><span>- Users use at least 3 times per week</span></span>
<span class="line"><span>- Core feature (add expense record) usage rate &gt; 80%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Key Performance Indicators (KPIs):</span></span>
<span class="line"><span>- User retention rate: 7-day retention &gt; 30%, 30-day retention &gt; 15%</span></span>
<span class="line"><span>- Core feature usage rate: Add expense record usage &gt; 80%</span></span>
<span class="line"><span>- Task completion time: Add one expense &lt; 30 seconds</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Validation Methods:</span></span>
<span class="line"><span>- Record user behavior through backend logs</span></span>
<span class="line"><span>- Use A/B testing to verify user retention</span></span>
<span class="line"><span>- Collect satisfaction through user feedback surveys</span></span></code></pre></div><h3 id="pitfall-8-unverifiable-assumptions" tabindex="-1">Pitfall 8: Unverifiable Assumptions <a class="header-anchor" href="#pitfall-8-unverifiable-assumptions" aria-label="Permalink to &quot;Pitfall 8: Unverifiable Assumptions&quot;">​</a></h3><p><strong>Bad Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Assumption: Users will like our design</span></span></code></pre></div><p><strong>Consequence</strong>: Cannot be verified through user research, MVP may fail.</p><p><strong>Recommendation</strong>: Write verifiable assumptions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Assumptions:</span></span>
<span class="line"><span>Market Assumptions:</span></span>
<span class="line"><span>- Young people (18-30 years old) have the pain point of &quot;not knowing where money went&quot;</span></span>
<span class="line"><span>- Existing expense tracking apps are too complex, young people need a simpler solution</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Behavior Assumptions:</span></span>
<span class="line"><span>- Users are willing to spend 2 minutes recording expenses after each purchase if it helps control budget</span></span>
<span class="line"><span>- Users prefer minimalist UI, don&#39;t need complex charts and analysis</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Technical Feasibility Assumptions:</span></span>
<span class="line"><span>- Mobile apps can achieve a fast 3-step expense tracking flow</span></span>
<span class="line"><span>- Offline storage can meet basic requirements</span></span></code></pre></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>The core of the PRD stage is <strong>defining requirements, not implementation</strong>:</p><ol><li><strong>Input</strong>: Structured <code>input/idea.md</code> (Bootstrap stage output)</li><li><strong>Process</strong>: AI assistant uses thinking frameworks from <code>skills/prd/skill.md</code> and MoSCoW priority framework</li><li><strong>Output</strong>: Complete <code>artifacts/prd/prd.md</code> document</li><li><strong>Validation</strong>: Check whether users are clear, value is quantifiable, features are focused, and whether technical details are included</li></ol><div class="tip custom-block"><p class="custom-block-title">Key Principles</p><ul><li>❌ What not to do: Don&#39;t discuss technical implementation, don&#39;t design UI layout, don&#39;t decide database structure</li><li>✅ What to do: Define target users, list core features, clarify MVP scope, provide testable user stories</li></ul></div><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../stage-ui/">Stage 3: UI - Design Interface and Prototypes</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to design UI structure based on PRD</li><li>How to use ui-ux-pro-max skill to generate design systems</li><li>How to generate previewable HTML prototypes</li><li>Output files and exit criteria for UI stage</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>PRD Agent definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/prd.agent.md" target="_blank" rel="noreferrer"><code>agents/prd.agent.md</code></a></td><td>1-33</td></tr><tr><td>PRD Skill</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/skills/prd/skill.md" target="_blank" rel="noreferrer"><code>skills/prd/skill.md</code></a></td><td>1-325</td></tr><tr><td>Pipeline definition (PRD stage)</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>20-33</td></tr><tr><td>Scheduler definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-100+</td></tr></tbody></table><p><strong>Key Constraints</strong>:</p><ul><li><strong>Prohibit technical implementation details</strong>: prd.agent.md:23</li><li><strong>Prohibit UI design descriptions</strong>: prd.agent.md:23</li><li><strong>Must include target users</strong>: pipeline.yaml:29</li><li><strong>Must define MVP scope</strong>: pipeline.yaml:30</li><li><strong>Must list non-goals</strong>: pipeline.yaml:31</li><li><strong>Output file must be saved to artifacts/prd/prd.md</strong>: prd.agent.md:13</li></ul><p><strong>Exit Criteria</strong> (pipeline.yaml:28-32):</p><ul><li>PRD includes target users</li><li>PRD defines MVP scope</li><li>PRD lists non-goals (Out of Scope)</li><li>PRD contains no technical implementation details</li></ul><p><strong>Skill Content Framework</strong>:</p><ul><li><strong>Thinking Framework</strong>: Target users, core problem, core value, success metrics</li><li><strong>MoSCoW Feature Priority Framework</strong>: Must Have, Should Have, Could Have, Won&#39;t Have</li><li><strong>User Story Writing Guidelines</strong>: Standard format and examples</li><li><strong>PRD Document Structure Requirements</strong>: 8 required sections</li><li><strong>Decision Principles</strong>: User-centered, focus on MVP, clear non-goals, testability</li><li><strong>Quality Checklist</strong>: Users and problems, feature scope, user stories, document completeness, prohibited items check</li><li><strong>NEVER</strong>: 7 explicitly prohibited behaviors</li></ul><p><strong>PRD Document Required Sections</strong>:</p><ol><li>Overview (product overview, background, and goals)</li><li>Target User Persona (primary user groups, secondary user groups)</li><li>Core Value Proposition (problem solved, our solution, differentiation advantages)</li><li>Feature Requirements (Must Have, Should Have, Could Have)</li><li>User Flow (main process description)</li><li>Non-goals (Won&#39;t Have)</li><li>Success Metrics (product goals, key metrics, validation methods)</li><li>Assumptions and Risks (market assumptions, user behavior assumptions, technical feasibility assumptions, risk table)</li></ol></details>`,120)])])}const g=s(i,[["render",o]]);export{h as __pageData,g as default};
